from vex_sdk import Vex, Guardrail

vex = Vex(api_key="your-vex-key")

source_faithfulness_guardrail = Guardrail(
    name="source-faithfulness",
    verifiers=[
        {
            "type": "semantic_similarity",
            "threshold": 0.85,
            "reference_extraction": {
                "type": "from_pydantic",
                "model": "AttributedResponse",
                "fields": ["answer"]
            },
            "candidate_extraction": {
                "type": "from_agent_context",
                "retrieval_results_key": "chunks"
            }
        }
    ]
)

# Attach to synthesizer agent
synthesizer_agent.result_validator = vex.validate(
    guardrail=source_faithfulness_guardrail
)

citation_guardrail = Guardrail(
    name="citation-verification",
    verifiers=[
        {
            "type": "citation_check",
            "citations_field": "citations",
            "retrieved_chunks_field": "chunks",
            "require_all_claims_cited": True,
            "max_citation_distance": 3
        },
        {
            "type": "no_phantom_citations",
            "citations_field": "citations"
        }
    ]
)

# Apply to final orchestrator
orchestrator.vex_guardrail = vex.validate(
    guardrail=citation_guardrail
)

planning_guardrail = Guardrail(
    name="query-planning-coverage",
    verifiers=[
        {
            "type": "intent_coverage",
            "original_query_field": "question",
            "planned_queries_field": "sub_queries",
            "min_coverage_score": 0.9,
            "max_entities_missed": 1
        },
        {
            "type": "no_redundant_queries",
            "queries_field": "sub_queries",
            "max_similarity": 0.7
        }
    ]
)

planner_agent.result_validator = vex.validate(
    guardrail=planning_guardrail
)
